from __future__ import annotations

# cascade variant: evaluator rendered against updated parser code

from parser import Binary, Call, Number, ParseError, parse


class EvalError(Exception):
    pass


def _clean(value: float) -> int | float:
    return int(value) if value.is_integer() else value


def _apply(name: str, args: list[float]) -> float:
    if name == "add" and len(args) == 2:
        return args[0] + args[1]
    if name == "sub" and len(args) == 2:
        return args[0] - args[1]
    if name == "mul" and len(args) == 2:
        return args[0] * args[1]
    if name == "div" and len(args) == 2:
        if args[1] == 0:
            raise EvalError("divide by zero")
        return args[0] / args[1]
    if name == "max" and args:
        return max(args)
    if name == "min" and args:
        return min(args)
    raise EvalError(f"unknown name: {name}")


def _eval(node: object) -> float:
    if isinstance(node, Number):
        return node.value
    if isinstance(node, Binary):
        left = _eval(node.left)
        right = _eval(node.right)
        if node.operator == "+":
            return left + right
        if node.operator == "-":
            return left - right
        if node.operator == "*":
            return left * right
        if node.operator == "/":
            if right == 0:
                raise EvalError("divide by zero")
            return left / right
    if isinstance(node, Call):
        return _apply(node.name, [_eval(arg) for arg in node.args])
    raise EvalError("unsupported expression")


def evaluate(text: str) -> int | float:
    try:
        return _clean(_eval(parse(text)))
    except ParseError as exc:
        raise EvalError(f"syntax error: {exc}") from exc

